import{_ as o,C as i,o as a,c as l,a2 as t,b as r,w as n,a as c,E as d,a3 as p}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"Claude Code — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/claude-code/context-management.md","filePath":"research/agents/claude-code/context-management.md"}'),u={name:"research/agents/claude-code/context-management.md"};function m(h,e,g,b,x,f){const s=i("Mermaid");return a(),l("div",null,[e[1]||(e[1]=t(`<h1 id="claude-code-—-context-management" tabindex="-1">Claude Code — Context Management <a class="header-anchor" href="#claude-code-—-context-management" aria-label="Permalink to &quot;Claude Code — Context Management&quot;">​</a></h1><blockquote><p>How Claude Code manages its finite context window — the single most important resource in agentic coding.</p></blockquote><h2 id="the-core-constraint" tabindex="-1">The Core Constraint <a class="header-anchor" href="#the-core-constraint" aria-label="Permalink to &quot;The Core Constraint&quot;">​</a></h2><p>From Anthropic&#39;s best practices documentation:</p><blockquote><p>&quot;Most best practices are based on one constraint: Claude&#39;s context window fills up fast, and performance degrades as it fills.&quot;</p></blockquote><p>The context window holds: conversation history, file contents Claude has read, command outputs, CLAUDE.md instructions, loaded skills, auto-memory, MCP tool definitions, and system instructions. A single debugging session can consume tens of thousands of tokens. As context fills, Claude starts &quot;forgetting&quot; earlier instructions and makes more errors.</p><p><strong>Context management is the central design challenge of Claude Code.</strong> Nearly every architectural decision — sub-agents, skills, compaction, CLAUDE.md guidelines — exists to address this.</p><h2 id="context-management-mechanisms" tabindex="-1">Context Management Mechanisms <a class="header-anchor" href="#context-management-mechanisms" aria-label="Permalink to &quot;Context Management Mechanisms&quot;">​</a></h2><h3 id="_1-auto-compaction" tabindex="-1">1. Auto-Compaction <a class="header-anchor" href="#_1-auto-compaction" aria-label="Permalink to &quot;1. Auto-Compaction&quot;">​</a></h3><p>When Claude approaches the context limit, it automatically compacts conversation history:</p><ul><li><strong>Process</strong>: Clears older tool outputs first, then summarizes the conversation if needed</li><li><strong>Preserved</strong>: User requests, key code snippets, important decisions</li><li><strong>Lost</strong>: Detailed instructions from early in the conversation, verbose command outputs</li><li><strong>Configurable</strong>: Add &quot;Compact Instructions&quot; section to CLAUDE.md to control what&#39;s preserved</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># Example CLAUDE.md compact instructions</span></span>
<span class="line"><span>When compacting, always preserve:</span></span>
<span class="line"><span>- The full list of modified files</span></span>
<span class="line"><span>- All test commands and their results</span></span>
<span class="line"><span>- Architecture decisions made during this session</span></span></code></pre></div><h3 id="_2-manual-compaction-compact" tabindex="-1">2. Manual Compaction (<code>/compact</code>) <a class="header-anchor" href="#_2-manual-compaction-compact" aria-label="Permalink to &quot;2. Manual Compaction (\`/compact\`)&quot;">​</a></h3><p>Users can trigger compaction manually with focus instructions:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>/compact                            # General compaction</span></span>
<span class="line"><span>/compact Focus on the API changes   # Directed compaction</span></span>
<span class="line"><span>/compact Keep the test results      # Selective preservation</span></span></code></pre></div><p>This is useful when you know context is getting bloated but auto-compaction hasn&#39;t triggered yet.</p><h3 id="_3-selective-rewind-summarization" tabindex="-1">3. Selective Rewind Summarization <a class="header-anchor" href="#_3-selective-rewind-summarization" aria-label="Permalink to &quot;3. Selective Rewind Summarization&quot;">​</a></h3><p>Via <code>Esc + Esc</code> or <code>/rewind</code>, users can select a message checkpoint and choose <strong>&quot;Summarize from here&quot;</strong>:</p><ul><li>Condenses messages from the selected point forward</li><li>Keeps earlier context intact</li><li>Gives fine-grained control over what to compress vs. preserve</li></ul><h3 id="_4-clear-—-full-context-reset" tabindex="-1">4. <code>/clear</code> — Full Context Reset <a class="header-anchor" href="#_4-clear-—-full-context-reset" aria-label="Permalink to &quot;4. \`/clear\` — Full Context Reset&quot;">​</a></h3><p>Wipes the entire conversation context. Recommended:</p><ul><li>Between unrelated tasks</li><li>When you&#39;ve corrected Claude more than twice on the same issue</li><li>After long exploration sessions before implementation</li></ul><blockquote><p>&quot;A clean session with a better prompt almost always outperforms a long session with accumulated corrections.&quot;</p></blockquote><h3 id="_5-btw-—-side-questions" tabindex="-1">5. <code>/btw</code> — Side Questions <a class="header-anchor" href="#_5-btw-—-side-questions" aria-label="Permalink to &quot;5. \`/btw\` — Side Questions&quot;">​</a></h3><p>For quick questions that shouldn&#39;t enter the conversation history:</p><ul><li>Answer appears in a dismissible overlay</li><li>Never enters conversation context</li><li>Check details without growing context</li><li>Example: <code>/btw what&#39;s the syntax for Python f-strings?</code></li></ul><h2 id="context-loading-mechanisms" tabindex="-1">Context Loading Mechanisms <a class="header-anchor" href="#context-loading-mechanisms" aria-label="Permalink to &quot;Context Loading Mechanisms&quot;">​</a></h2><h3 id="claude-md-files" tabindex="-1">CLAUDE.md Files <a class="header-anchor" href="#claude-md-files" aria-label="Permalink to &quot;CLAUDE.md Files&quot;">​</a></h3><p>Persistent instructions loaded at the start of every session:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Location</th><th>Loading</th></tr></thead><tbody><tr><td>Managed policy</td><td>System dirs (<code>/Library/Application Support/ClaudeCode/</code>)</td><td>Always loaded, can&#39;t be excluded</td></tr><tr><td>Project root</td><td><code>./CLAUDE.md</code> or <code>./.claude/CLAUDE.md</code></td><td>Loaded at session start</td></tr><tr><td>Parent directories</td><td>Walking up from CWD</td><td>Loaded at session start</td></tr><tr><td>Child directories</td><td>Subdirectory CLAUDE.md files</td><td>Loaded on demand (when Claude reads files in that dir)</td></tr><tr><td>User</td><td><code>~/.claude/CLAUDE.md</code></td><td>Loaded at session start</td></tr></tbody></table><p><strong>Best practices for CLAUDE.md</strong>:</p><ul><li>Target under 200 lines per file</li><li>Every line should pass the test: &quot;Would removing this cause Claude to make mistakes?&quot;</li><li>Use specific, verifiable instructions (&quot;Use 2-space indentation&quot; not &quot;Format code properly&quot;)</li><li>Check for conflicts between multiple CLAUDE.md files</li><li>Use <code>@path/to/import</code> syntax to import additional files</li><li>Treat it like code: review when things go wrong, prune regularly</li></ul><h3 id="claude-rules-—-modular-project-rules" tabindex="-1"><code>.claude/rules/</code> — Modular Project Rules <a class="header-anchor" href="#claude-rules-—-modular-project-rules" aria-label="Permalink to &quot;\`.claude/rules/\` — Modular Project Rules&quot;">​</a></h3><p>For larger projects, instructions can be split into topic-specific files:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>.claude/</span></span>
<span class="line"><span>├── CLAUDE.md              # Main instructions</span></span>
<span class="line"><span>└── rules/</span></span>
<span class="line"><span>    ├── code-style.md      # Always loaded (no paths frontmatter)</span></span>
<span class="line"><span>    ├── testing.md          # Always loaded</span></span>
<span class="line"><span>    └── api-design.md      # Path-scoped (see below)</span></span></code></pre></div><p><strong>Path-scoped rules</strong> only load when Claude works with matching files:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;">---</span></span>
<span class="line"><span style="color:#89B4FA;">paths</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#A6E3A1;"> &quot;src/api/**/*.ts&quot;</span></span>
<span class="line"><span style="color:#F5C2E7;">---</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># API Development Rules</span></span>
<span class="line"><span style="color:#9399B2;">-</span><span style="color:#A6E3A1;"> All API endpoints must include input validation</span></span>
<span class="line"><span style="color:#9399B2;">-</span><span style="color:#A6E3A1;"> Use the standard error response format</span></span></code></pre></div><p>This reduces context waste — rules load only when relevant.</p><h3 id="auto-memory" tabindex="-1">Auto Memory <a class="header-anchor" href="#auto-memory" aria-label="Permalink to &quot;Auto Memory&quot;">​</a></h3><p>Claude&#39;s self-written notes that persist across sessions:</p><ul><li><strong>Storage</strong>: <code>~/.claude/projects/&lt;project&gt;/memory/MEMORY.md</code> + topic files</li><li><strong>Loading</strong>: First 200 lines of MEMORY.md at session start</li><li><strong>Topic files</strong>: Loaded on demand by Claude, not at startup</li><li><strong>Content</strong>: Build commands, debugging insights, architecture notes, code style preferences</li><li><strong>Shared scope</strong>: All worktrees/subdirectories within same git repo share one memory directory</li><li><strong>Machine-local</strong>: Not shared across machines or cloud environments</li></ul><h3 id="skills-—-on-demand-knowledge" tabindex="-1">Skills — On-Demand Knowledge <a class="header-anchor" href="#skills-—-on-demand-knowledge" aria-label="Permalink to &quot;Skills — On-Demand Knowledge&quot;">​</a></h3><p>Skills are knowledge packages that load only when relevant:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>.claude/skills/</span></span>
<span class="line"><span>└── api-conventions/</span></span>
<span class="line"><span>    └── SKILL.md</span></span></code></pre></div><ul><li>Claude sees skill descriptions at session start (minimal context cost)</li><li>Full skill content loads only when invoked or matched</li><li><code>disable-model-invocation: true</code> keeps descriptions out of context until <code>/skill-name</code> is used</li><li>Much more context-efficient than putting everything in CLAUDE.md</li></ul><h2 id="sub-agents-for-context-isolation" tabindex="-1">Sub-Agents for Context Isolation <a class="header-anchor" href="#sub-agents-for-context-isolation" aria-label="Permalink to &quot;Sub-Agents for Context Isolation&quot;">​</a></h2><p><strong>Sub-agents are the most powerful context management tool.</strong> They run in completely separate context windows:</p>`,47)),(a(),r(p,null,{default:n(()=>[d(s,{id:"mermaid-349",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22Main%20Context%20Window%3Cbr%2F%3EYour%20conversation%20(preserved)%3Cbr%2F%3E%2B%20compact%20summary%22%5D%0A%20%20%20%20B%5B%22Sub-Agent%20Context%20Window%3Cbr%2F%3EExploration%20task%3Cbr%2F%3EReads%2020%20files%3Cbr%2F%3ESearches%20codebase%3Cbr%2F%3EAnalyzes%20patterns%3Cbr%2F%3E(all%20discarded)%22%5D%0A%0A%20%20%20%20A%20--%3E%7C%22spawn%22%7C%20B%0A%20%20%20%20B%20--%3E%7C%22summary%22%7C%20A%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t(`<p><strong>Why this matters</strong>: When Claude explores a codebase, it reads many files — each consuming context. With sub-agents, the exploration happens in a separate window. Only the summary comes back. Your main conversation stays clean.</p><h3 id="built-in-sub-agents-and-context" tabindex="-1">Built-in Sub-Agents and Context <a class="header-anchor" href="#built-in-sub-agents-and-context" aria-label="Permalink to &quot;Built-in Sub-Agents and Context&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Context Impact on Main</th></tr></thead><tbody><tr><td><strong>Explore</strong> (Haiku)</td><td>Minimal — returns only findings summary</td></tr><tr><td><strong>Plan</strong> (inherits)</td><td>Minimal — returns research summary</td></tr><tr><td><strong>General-purpose</strong> (inherits)</td><td>Minimal — returns action summary</td></tr><tr><td><strong>Custom sub-agents</strong></td><td>Configurable via <code>maxTurns</code>, tool restrictions</td></tr></tbody></table><h3 id="prompting-for-sub-agent-use" tabindex="-1">Prompting for Sub-Agent Use <a class="header-anchor" href="#prompting-for-sub-agent-use" aria-label="Permalink to &quot;Prompting for Sub-Agent Use&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># Explicit delegation</span></span>
<span class="line"><span>Use subagents to investigate how our auth system handles token refresh</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Verification via sub-agent</span></span>
<span class="line"><span>Use a subagent to review this code for edge cases</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Research then implement</span></span>
<span class="line"><span>Use a subagent to explore the codebase structure, then implement the feature</span></span></code></pre></div><h2 id="mcp-server-context-costs" tabindex="-1">MCP Server Context Costs <a class="header-anchor" href="#mcp-server-context-costs" aria-label="Permalink to &quot;MCP Server Context Costs&quot;">​</a></h2><p>MCP servers add tool definitions to every API request. A few servers can consume significant context before any work begins.</p><ul><li><strong>Check costs</strong>: <code>/mcp</code> command shows per-server token costs</li><li><strong>Tool Search</strong>: When MCP tools exceed 10% of context, tools are deferred and loaded on demand</li><li><strong>Mitigation</strong>: Scope MCP servers to sub-agents to keep definitions out of main context</li></ul><h2 id="context-—-monitor-context-usage" tabindex="-1"><code>/context</code> — Monitor Context Usage <a class="header-anchor" href="#context-—-monitor-context-usage" aria-label="Permalink to &quot;\`/context\` — Monitor Context Usage&quot;">​</a></h2><p>The <code>/context</code> command shows what&#39;s using space in the context window. Use it to:</p><ul><li>Identify bloated conversation history</li><li>See MCP tool definition costs</li><li>Decide when to <code>/clear</code> or <code>/compact</code></li></ul><h2 id="context-aware-workflow-patterns" tabindex="-1">Context-Aware Workflow Patterns <a class="header-anchor" href="#context-aware-workflow-patterns" aria-label="Permalink to &quot;Context-Aware Workflow Patterns&quot;">​</a></h2><h3 id="pattern-1-explore-→-clear-→-implement" tabindex="-1">Pattern 1: Explore → Clear → Implement <a class="header-anchor" href="#pattern-1-explore-→-clear-→-implement" aria-label="Permalink to &quot;Pattern 1: Explore → Clear → Implement&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. Explore codebase with questions</span></span>
<span class="line"><span>2. /clear</span></span>
<span class="line"><span>3. Start fresh with implementation prompt incorporating learnings</span></span></code></pre></div><h3 id="pattern-2-sub-agent-exploration" tabindex="-1">Pattern 2: Sub-Agent Exploration <a class="header-anchor" href="#pattern-2-sub-agent-exploration" aria-label="Permalink to &quot;Pattern 2: Sub-Agent Exploration&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. &quot;Use a sub-agent to explore src/auth/ and summarize the architecture&quot;</span></span>
<span class="line"><span>2. Receive compact summary</span></span>
<span class="line"><span>3. &quot;Now implement OAuth2 support based on that architecture&quot;</span></span></code></pre></div><h3 id="pattern-3-plan-mode-→-new-session" tabindex="-1">Pattern 3: Plan Mode → New Session <a class="header-anchor" href="#pattern-3-plan-mode-→-new-session" aria-label="Permalink to &quot;Pattern 3: Plan Mode → New Session&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. claude --permission-mode plan</span></span>
<span class="line"><span>2. Research and create a detailed plan</span></span>
<span class="line"><span>3. Plan saved to file</span></span>
<span class="line"><span>4. Start new session with clean context</span></span>
<span class="line"><span>5. &quot;Implement the plan in SPEC.md&quot;</span></span></code></pre></div><h3 id="pattern-4-session-naming-and-resume" tabindex="-1">Pattern 4: Session Naming and Resume <a class="header-anchor" href="#pattern-4-session-naming-and-resume" aria-label="Permalink to &quot;Pattern 4: Session Naming and Resume&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>claude --name &quot;oauth-migration&quot;</span></span>
<span class="line"><span># ... work on task ...</span></span>
<span class="line"><span># Later:</span></span>
<span class="line"><span>claude --resume  # Find by name, resume with preserved context</span></span></code></pre></div><h2 id="key-observations" tabindex="-1">Key Observations <a class="header-anchor" href="#key-observations" aria-label="Permalink to &quot;Key Observations&quot;">​</a></h2><ol><li><p><strong>Context is explicitly the #1 concern</strong>: Anthropic&#39;s documentation centers virtually all best practices around context management. This is unusually transparent about the fundamental limitation.</p></li><li><p><strong>Multiple compaction strategies</strong>: Auto-compaction + manual <code>/compact</code> + selective rewind summarization + <code>/clear</code> + <code>/btw</code> — five different granularities of context control. No other coding agent offers this many.</p></li><li><p><strong>CLAUDE.md survives compaction</strong>: After <code>/compact</code>, CLAUDE.md is re-read from disk and re-injected fresh. This is a key design decision — project instructions are never lost to compaction.</p></li><li><p><strong>Sub-agents are a context architecture, not just delegation</strong>: The primary motivation for sub-agents isn&#39;t task specialization — it&#39;s context isolation. This is made explicit in the docs.</p></li><li><p><strong>Skills vs. CLAUDE.md trade-off</strong>: CLAUDE.md is always loaded (cost: every session). Skills load on demand (cost: only when needed). This is a deliberate design tension for context budgeting.</p></li><li><p><strong>200-line limits are everywhere</strong>: CLAUDE.md recommended &lt; 200 lines, auto-memory loads first 200 lines. This number appears to be a practical token budget threshold.</p></li></ol>`,22))])}const v=o(u,[["render",m]]);export{y as __pageData,v as default};
